1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	};
10	
11	type Item = { type: string };
12	type Step = { items: Item[] };
13	type Scenario = { steps: Step[] };
14	
15	const basePremiumFor = (item: Item): number =>
16	  BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;
17	
18	const sumBasePremiums = (items: Item[]): number =>
19	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
20	
21	const quotePremiumFor = (step: Step): number =>
22	  sumBasePremiums(step.items) + PROCESSING_FEE;
23	
24	export const processScenario = (input: unknown): unknown => {
25	  const scenario = input as Scenario;
26	  return { results: [{ premium: quotePremiumFor(scenario.steps[0]) }] };
27	};
